import React from 'react';
import './HeatmapDashboard.css';

const HeatmapDashboard = ({ language }) => {
  const content = {
    en: {
      title: 'Severity Heatmap Dashboard',
      totalCases: 'Total Cases',
      highSeverity: 'High Severity',
      patternAlerts: 'Pattern Alerts',
      locations: 'Locations',
      hostel: 'Hostels',
      department: 'Departments',
      campus: 'Campus Areas',
      offCampus: 'Off-Campus'
    },
    hi: {
      title: 'गंभीरता हीटमैप डैशबोर्ड',
      totalCases: 'कुल मामले',
      highSeverity: 'उच्च गंभीरता',
      patternAlerts: 'पैटर्न अलर्ट',
      locations: 'स्थान',
      hostel: 'छात्रावास',
      department: 'विभाग',
      campus: 'कैंपस क्षेत्र',
      offCampus: 'कैंपस के बाहर'
    }
  };

  const text = content[language] || content.en;

  // Mock data
  const stats = { total: 45, highSeverity: 12, patterns: 3 };
  const locations = [
    { name: text.hostel, count: 18, severity: 'high' },
    { name: text.department, count: 15, severity: 'medium' },
    { name: text.campus, count: 8, severity: 'low' },
    { name: text.offCampus, count: 4, severity: 'medium' }
  ];

  return (
    <div className="heatmap-dashboard">
      <div className="dashboard-container">
        <h1>{text.title}</h1>

        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-value">{stats.total}</div>
            <div className="stat-label">{text.totalCases}</div>
          </div>
          <div className="stat-card high">
            <div className="stat-value">{stats.highSeverity}</div>
            <div className="stat-label">{text.highSeverity}</div>
          </div>
          <div className="stat-card alert">
            <div className="stat-value">{stats.patterns}</div>
            <div className="stat-label">{text.patternAlerts}</div>
          </div>
        </div>

        <div className="heatmap-section">
          <h2>{text.locations}</h2>
          <div className="heatmap-bars">
            {locations.map((loc, i) => (
              <div key={i} className="heatmap-bar">
                <div className="bar-label">{loc.name}</div>
                <div className="bar-container">
                  <div 
                    className={`bar-fill ${loc.severity}`}
                    style={{ width: `${(loc.count / stats.total) * 100}%` }}
                  >
                    {loc.count}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default HeatmapDashboard;
